"""Launch vLLM with a bounded NxD HLO compilation thread pool."""

import concurrent.futures
import json
import os
import runpy
from pathlib import Path


DEFAULT_COMPILE_MAX_WORKERS = 8
_original_engine_core_entrypoint = None
_original_kv_quantization_config_init = None


def get_compile_max_workers() -> int:
    raw_value = os.environ.get(
        "NXD_COMPILE_MAX_WORKERS", str(DEFAULT_COMPILE_MAX_WORKERS)
    )
    try:
        max_workers = int(raw_value)
    except ValueError as exc:
        raise SystemExit("NXD_COMPILE_MAX_WORKERS must be a positive integer") from exc
    if max_workers < 1:
        raise SystemExit("NXD_COMPILE_MAX_WORKERS must be a positive integer")
    return max_workers


class _FuturesProxy:
    def __init__(self, default_max_workers: int) -> None:
        self.default_max_workers = default_max_workers

    def ThreadPoolExecutor(self, max_workers=None, *args, **kwargs):
        if max_workers is None:
            max_workers = self.default_max_workers
        return concurrent.futures.ThreadPoolExecutor(
            max_workers=max_workers, *args, **kwargs
        )

    def __getattr__(self, name):
        return getattr(concurrent.futures, name)


class _ConcurrentProxy:
    def __init__(self, default_max_workers: int) -> None:
        self.futures = _FuturesProxy(default_max_workers)


def limit_nxd_compile_workers(max_workers: int) -> None:
    from neuronx_distributed.trace import model_builder

    # ModelBuilder creates an unbounded-by-workload executor. Replace only its
    # module reference so other vLLM thread pools keep their original defaults.
    model_builder.concurrent = _ConcurrentProxy(max_workers)


def normalize_kv_quant_dtype(kv_quant_config: dict) -> None:
    quant_dtype = kv_quant_config.get("quant_dtype")
    if isinstance(quant_dtype, str):
        import torch

        try:
            dtype = getattr(torch, quant_dtype)
        except AttributeError as exc:
            raise ValueError(
                f"Unsupported KV-cache quantization dtype: {quant_dtype!r}"
            ) from exc
        if not isinstance(dtype, torch.dtype):
            raise ValueError(
                f"Unsupported KV-cache quantization dtype: {quant_dtype!r}"
            )
        kv_quant_config["quant_dtype"] = dtype

    serialized_methods = [
        name
        for name in ("k_quant_method", "v_quant_method")
        if isinstance(kv_quant_config.get(name), dict)
    ]
    if not serialized_methods:
        return

    from neuronx_distributed.quantization.quantization_config import (
        QuantizationType,
    )

    for name in serialized_methods:
        kv_quant_config[name] = QuantizationType(kv_quant_config[name]["_value_"])


def _kv_quantization_config_init_with_torch_dtype(self, **kwargs):
    normalize_kv_quant_dtype(kwargs)
    return _original_kv_quantization_config_init(self, **kwargs)


def install_kv_quant_dtype_hook() -> None:
    global _original_kv_quantization_config_init

    from neuronx_distributed.quantization.quantization_config import (
        KVQuantizationConfig,
    )

    if (
        KVQuantizationConfig.__init__
        is _kv_quantization_config_init_with_torch_dtype
    ):
        return
    _original_kv_quantization_config_init = KVQuantizationConfig.__init__
    KVQuantizationConfig.__init__ = _kv_quantization_config_init_with_torch_dtype


def _signal_compile_only_complete(compiled_path: str) -> None:
    marker_value = os.environ.get("NEURON_COMPILE_ONLY_MARKER")
    if not marker_value:
        raise RuntimeError(
            "NEURON_COMPILE_ONLY_MARKER must be set when NEURON_COMPILE_ONLY=1"
        )
    marker = Path(marker_value)
    marker.parent.mkdir(parents=True, exist_ok=True)
    marker.write_text(f"{compiled_path}\n")
    raise SystemExit(0)


def _compiled_artifact_is_complete(compiled_path: str) -> bool:
    artifact_dir = Path(compiled_path)
    config_path = artifact_dir / "neuron_config.json"
    if not (artifact_dir / "model.pt").is_file() or not config_path.is_file():
        return False

    config = json.loads(config_path.read_text()).get("neuron_config", {})
    if not config.get("save_sharded_checkpoint", False):
        return True

    world_size = int(config.get("world_size", 0))
    return world_size > 0 and all(
        (
            artifact_dir
            / "weights"
            / f"tp{rank}_sharded_checkpoint.safetensors"
        ).is_file()
        for rank in range(world_size)
    )


def _compile_model_without_loading(
    application, model_path, neuronx_model_cls, config, compiled_path
):
    application.model = neuronx_model_cls(model_path, config)
    if config.neuron_config.quantized:
        neuronx_model_cls.save_quantized_state_dict(model_path, config)
    application.model.compile(compiled_path)
    _signal_compile_only_complete(compiled_path)


def _reuse_compiled_model_without_loading(
    application, compiled_path, neuronx_model_cls, kwargs
):
    if not _compiled_artifact_is_complete(compiled_path):
        raise FileNotFoundError(f"Incomplete compiled artifacts at {compiled_path}")
    _signal_compile_only_complete(compiled_path)


def install_compile_only_hook() -> None:
    if os.environ.get("NEURON_COMPILE_ONLY", "0") != "1":
        return

    from vllm_neuron.worker.neuronx_distributed_model_loader import NeuronModelBase

    NeuronModelBase._compile_and_load_model = _compile_model_without_loading
    NeuronModelBase._load_compiled_model = _reuse_compiled_model_without_loading


def _run_with_limited_nxd_workers(target, *args, **kwargs):
    max_workers = get_compile_max_workers()
    limit_nxd_compile_workers(max_workers)
    install_kv_quant_dtype_hook()
    install_compile_only_hook()
    print(f"NxD HLO compile workers in EngineCore: {max_workers}", flush=True)
    return target(*args, **kwargs)


def _run_engine_core_with_limited_nxd_workers(*args, **kwargs):
    target = _original_engine_core_entrypoint
    if target is None:
        from vllm.v1.engine.core import EngineCoreProc

        target = EngineCoreProc.run_engine_core
    return _run_with_limited_nxd_workers(target, *args, **kwargs)


def install_engine_core_worker_hook() -> None:
    global _original_engine_core_entrypoint

    from vllm.v1.engine.core import EngineCoreProc

    if EngineCoreProc.run_engine_core is _run_engine_core_with_limited_nxd_workers:
        return
    _original_engine_core_entrypoint = EngineCoreProc.run_engine_core
    EngineCoreProc.run_engine_core = staticmethod(
        _run_engine_core_with_limited_nxd_workers
    )


def main() -> None:
    max_workers = get_compile_max_workers()
    limit_nxd_compile_workers(max_workers)
    install_engine_core_worker_hook()
    print(f"NxD HLO compile workers: {max_workers}", flush=True)
    runpy.run_module("vllm.entrypoints.openai.api_server", run_name="__main__")


if __name__ == "__main__":
    main()

"""Capacity-aware routing for replicated planning endpoints."""

from contextlib import contextmanager
from pathlib import Path
from threading import Condition
from time import monotonic, sleep
from typing import Mapping


def parse_planning_ports(value: str | None, fallback_port: int) -> list[int]:
    if not value:
        return [fallback_port]

    ports: list[int] = []
    for item in value.split(","):
        item = item.strip()
        if not item:
            continue
        if "-" in item:
            start_text, end_text = item.split("-", 1)
            try:
                start, end = int(start_text), int(end_text)
            except ValueError as exc:
                raise ValueError(f"invalid planning port range: {item}") from exc
            if end < start:
                raise ValueError(f"invalid planning port range: {item}")
            ports.extend(range(start, end + 1))
        else:
            try:
                ports.append(int(item))
            except ValueError as exc:
                raise ValueError(f"invalid planning port: {item}") from exc

    if not ports:
        raise ValueError("--planning-ports must contain at least one port")
    if any(port < 1 or port > 65535 for port in ports):
        raise ValueError("planning ports must be in the range 1..65535")
    if len(set(ports)) != len(ports):
        raise ValueError("planning ports must not contain duplicates")
    return ports


def parse_planning_endpoint_capacities(
    value: str | None,
    ports: list[int],
    fallback_capacity: int,
) -> dict[int, int]:
    """Parse optional ``port:capacity`` overrides for a planning endpoint set."""
    if fallback_capacity < 1:
        raise ValueError("planning endpoint capacity must be positive")

    capacities = {port: fallback_capacity for port in ports}
    if not value:
        return capacities

    overridden_ports: set[int] = set()
    for item in value.split(","):
        item = item.strip()
        if not item:
            continue
        try:
            port_text, capacity_text = item.split(":", 1)
            port = int(port_text)
            capacity = int(capacity_text)
        except ValueError as exc:
            raise ValueError(
                f"invalid planning endpoint capacity {item!r}; use port:capacity"
            ) from exc
        if port not in capacities:
            raise ValueError(f"capacity given for unknown planning port: {port}")
        if port in overridden_ports:
            raise ValueError(f"duplicate capacity given for planning port: {port}")
        if capacity < 1:
            raise ValueError("planning endpoint capacities must be positive")
        capacities[port] = capacity
        overridden_ports.add(port)

    if not overridden_ports:
        raise ValueError("--planning-endpoint-capacities must contain at least one port:capacity")
    return capacities


class PlanningEndpointPool:
    def __init__(
        self,
        ports: list[int],
        capacity_per_endpoint: int | Mapping[int, int],
    ) -> None:
        if not ports:
            raise ValueError("at least one planning endpoint is required")

        self.ports = tuple(ports)
        if isinstance(capacity_per_endpoint, int):
            if capacity_per_endpoint < 1:
                raise ValueError("planning endpoint capacity must be positive")
            self.capacity_by_port = {
                port: capacity_per_endpoint for port in self.ports
            }
        else:
            if set(capacity_per_endpoint) != set(self.ports):
                raise ValueError("endpoint capacities must specify exactly the planning ports")
            if any(capacity < 1 for capacity in capacity_per_endpoint.values()):
                raise ValueError("planning endpoint capacities must be positive")
            self.capacity_by_port = dict(capacity_per_endpoint)

        self._available = dict(self.capacity_by_port)
        self._retired: set[int] = set()
        self._recovering: set[int] = set()
        self._condition = Condition()
        self._next_port_index = 0
        self._home_port_index = 0

    def _next_available_port(self) -> int | None:
        for offset in range(len(self.ports)):
            index = (self._next_port_index + offset) % len(self.ports)
            port = self.ports[index]
            if self._available[port] > 0:
                self._next_port_index = (index + 1) % len(self.ports)
                return port
        return None

    def _all_retired(self) -> bool:
        return len(self._retired) == len(self.ports)

    def assign_home(self) -> int:
        """Return a stable preferred endpoint without reserving its capacity."""
        with self._condition:
            while True:
                if self._all_retired():
                    raise RuntimeError("all planning endpoints have been retired")
                for offset in range(len(self.ports)):
                    index = (self._home_port_index + offset) % len(self.ports)
                    port = self.ports[index]
                    if port not in self._retired and port not in self._recovering:
                        self._home_port_index = (index + 1) % len(self.ports)
                        return port
                self._condition.wait()

    def acquire(
        self,
        preferred_port: int | None = None,
        affinity_timeout: float = 0.0,
        allow_fallback: bool = True,
    ) -> int:
        """Lease one request slot, optionally requiring its preferred endpoint."""
        if preferred_port is not None and preferred_port not in self.ports:
            raise ValueError(f"unknown planning port: {preferred_port}")
        if affinity_timeout < 0:
            raise ValueError("affinity_timeout must be non-negative")
        if not allow_fallback and preferred_port is None:
            raise ValueError("a preferred planning port is required without fallback")

        deadline = monotonic() + affinity_timeout
        with self._condition:
            while True:
                if self._all_retired():
                    raise RuntimeError("all planning endpoints have been retired")

                if not allow_fallback and preferred_port in self._retired:
                    raise RuntimeError(
                        f"preferred planning port {preferred_port} has been retired"
                    )

                if (
                    preferred_port is not None
                    and preferred_port not in self._retired
                    and preferred_port not in self._recovering
                    and self._available[preferred_port] > 0
                ):
                    self._available[preferred_port] -= 1
                    return preferred_port

                if not allow_fallback:
                    self._condition.wait()
                    continue

                now = monotonic()
                if preferred_port is None or now >= deadline:
                    port = self._next_available_port()
                    if port is not None:
                        self._available[port] -= 1
                        return port
                    self._condition.wait()
                else:
                    self._condition.wait(timeout=deadline - now)

    def retire(self, port: int) -> bool:
        """Permanently remove a known-dead endpoint for this client process."""
        if port not in self.ports:
            raise ValueError(f"unknown planning port: {port}")
        with self._condition:
            if port in self._retired:
                return False
            self._retired.add(port)
            self._recovering.discard(port)
            self._available[port] = 0
            self._condition.notify_all()
            return True

    def begin_recovery(self, port: int) -> bool:
        """Temporarily remove an endpoint while its local supervisor restarts it."""
        if port not in self.ports:
            raise ValueError(f"unknown planning port: {port}")
        with self._condition:
            if port in self._retired or port in self._recovering:
                return False
            self._recovering.add(port)
            self._available[port] = 0
            self._condition.notify_all()
            return True

    def restore(self, port: int) -> None:
        """Mark a recovered endpoint available after outstanding leases unwind."""
        if port not in self.ports:
            raise ValueError(f"unknown planning port: {port}")
        with self._condition:
            self._recovering.discard(port)
            self._available[port] = 0
            self._condition.notify_all()

    def release(self, port: int) -> None:
        if port not in self.ports:
            raise ValueError(f"unknown planning port: {port}")
        with self._condition:
            if port in self._retired or port in self._recovering:
                self._condition.notify_all()
                return
            if self._available[port] >= self.capacity_by_port[port]:
                raise ValueError(f"planning port {port} released too many times")
            self._available[port] += 1
            self._condition.notify_all()

    @contextmanager
    def endpoint(
        self,
        preferred_port: int | None = None,
        affinity_timeout: float = 0.0,
    ):
        port = self.acquire(preferred_port, affinity_timeout)
        try:
            yield port
        finally:
            self.release(port)


class PlanningEndpointRestartController:
    """Coordinate per-port restarts with the local Bash server supervisor."""

    def __init__(self, restart_dir: str | Path, timeout_seconds: float) -> None:
        if timeout_seconds <= 0:
            raise ValueError("planning restart timeout must be positive")
        self.restart_dir = Path(restart_dir)
        self.timeout_seconds = timeout_seconds
        self._condition = Condition()
        self._recovering: set[int] = set()
        self._results: dict[int, bool] = {}

    def _generation_path(self, port: int) -> Path:
        return self.restart_dir / f"tongyi-{port}.generation"

    def _request_path(self, port: int, generation: int) -> Path:
        return self.restart_dir / f"tongyi-{port}.restart.{generation}"

    def current_generation(self, port: int) -> int:
        try:
            return int(self._generation_path(port).read_text(encoding="utf-8").strip())
        except (OSError, ValueError):
            return 0

    def restart(
        self,
        port: int,
        endpoint_pool: PlanningEndpointPool,
        previous_generation: int,
    ) -> bool:
        """Request one restart and wait for a new ready generation or timeout."""
        with self._condition:
            if port in self._recovering:
                while port in self._recovering:
                    self._condition.wait()
                return self._results.get(port, False)
            self._recovering.add(port)

        recovered = False
        try:
            endpoint_pool.begin_recovery(port)
            self.restart_dir.mkdir(parents=True, exist_ok=True)
            if self.current_generation(port) > previous_generation:
                recovered = True
                return recovered
            self._request_path(port, previous_generation).touch(exist_ok=True)
            deadline = monotonic() + self.timeout_seconds
            while monotonic() < deadline:
                if self.current_generation(port) > previous_generation:
                    recovered = True
                    break
                sleep(0.5)
            return recovered
        finally:
            if recovered:
                endpoint_pool.restore(port)
            else:
                endpoint_pool.retire(port)
            with self._condition:
                self._results[port] = recovered
                self._recovering.discard(port)
                self._condition.notify_all()

